import{_ as t,o as a,c as i,a4 as o}from"./chunks/framework.DBZEZKAP.js";const p=JSON.parse('{"title":"Code Search","description":"","frontmatter":{},"headers":[],"relativePath":"search.md","filePath":"search.md","lastUpdated":null}'),n={name:"search.md"};function s(r,e,d,l,c,h){return a(),i("div",null,[...e[0]||(e[0]=[o(`<h1 id="Code-Search" tabindex="-1">Code Search <a class="header-anchor" href="#Code-Search" aria-label="Permalink to &quot;Code Search {#Code-Search}&quot;">​</a></h1><p>Kaimon gives you <strong>two complementary tools</strong> for finding code, both repo-scoped, <code>.gitignore</code>-aware, and richer than shell <code>grep</code>/<code>find</code> (every hit carries its enclosing function or struct):</p><ul><li><p><strong><code>search_code</code></strong> — find code by <strong>meaning</strong>. Describe a concept or behaviour (&quot;function that handles HTTP routing&quot;) and a hybrid semantic + lexical engine returns one ranked list. Reach for it when exploring or when you can&#39;t name what you&#39;re looking for — it&#39;s the default for learning a codebase.</p></li><li><p><strong><code>grep_code</code></strong> — find an <strong>exact pattern</strong>. Give it a literal string or regex (a symbol, a call site, a <code>TODO</code>) and it runs a real regex over the live working tree, returning every match with its enclosing symbol.</p></li></ul><p>Rule of thumb: <strong>describe it → <code>search_code</code>; already hold the exact token → <code>grep_code</code>.</strong> Default to <code>search_code</code> when exploring — <code>grep_code</code> only finds the text you type, so it can&#39;t see synonyms, indirection, or code you didn&#39;t know to name; guessing a symbol and grepping it is the classic miss. Reach for <code>grep_code</code> the moment you have a real identifier or string in hand. Most of this page covers <code>search_code</code> (the semantic engine); <code>grep_code</code> is summarized in its own section at the end.</p><p><img src="https://github.com/kahliburke/Kaimon.jl/releases/download/docs-assets/kaimon_search.gif" alt=""></p><h2 id="How-It-Works" tabindex="-1">How It Works <a class="header-anchor" href="#How-It-Works" aria-label="Permalink to &quot;How It Works {#How-It-Works}&quot;">​</a></h2><ol><li><p>Source files are split into <strong>chunks</strong> (function definitions, struct definitions, and sliding text windows).</p></li><li><p>Each chunk is converted into a vector embedding using a local Ollama model <strong>and</strong> mirrored into a local SQLite/FTS5 full-text index.</p></li><li><p>Embeddings are stored in a Qdrant vector database; the chunk text + metadata are stored in the lexical index.</p></li><li><p>When you search, the query is embedded and compared against stored vectors (semantic), and matched against the full-text index (lexical). The two ranked lists are fused with <a href="https://en.wikipedia.org/wiki/Learning_to_rank" target="_blank" rel="noreferrer">Reciprocal Rank Fusion</a> so a chunk found by both rises to the top.</p></li></ol><p>All processing happens locally — no code leaves your machine.</p><h2 id="Hybrid-Search-Semantic-Lexical" tabindex="-1">Hybrid Search (Semantic + Lexical) <a class="header-anchor" href="#Hybrid-Search-Semantic-Lexical" aria-label="Permalink to &quot;Hybrid Search (Semantic + Lexical) {#Hybrid-Search-Semantic-Lexical}&quot;">​</a></h2><p>The lexical half is a local SQLite/FTS5 index with two tokenizers — word-level (<code>get_ollama_embedding</code> → <code>get</code>/<code>ollama</code>/<code>embedding</code>) and trigram (substring, so <code>eval_with</code> finds <code>_eval_with_capture</code>). It catches exactly what embeddings miss: exact identifiers, error strings, config keys, and rare tokens. The keyword half also supports FTS query syntax — phrases (<code>&quot;exact phrase&quot;</code>), boolean (<code>memory AND leak</code>), and prefix (<code>mem*</code>) — through the same query box.</p><h3 id="modes" tabindex="-1">Modes <a class="header-anchor" href="#modes" aria-label="Permalink to &quot;Modes&quot;">​</a></h3><p><code>search_code</code> takes an optional <code>mode</code>:</p><table tabindex="0"><thead><tr><th style="text-align:right;">Mode</th><th style="text-align:right;">Behavior</th></tr></thead><tbody><tr><td style="text-align:right;"><code>hybrid</code> (default)</td><td style="text-align:right;">Semantic + lexical, fused. Best results; no need to think about it.</td></tr><tr><td style="text-align:right;"><code>semantic</code></td><td style="text-align:right;">Vector search only.</td></tr><tr><td style="text-align:right;"><code>lexical</code></td><td style="text-align:right;">Exact keyword/identifier only. <strong>Works even when Ollama/Qdrant are down</strong> (the index is local SQLite).</td></tr></tbody></table><p>Each result is tagged with its origin: <code>⚯</code> found by both, <code>≈</code> semantic, <code>⚡</code> exact keyword, <code>⊂</code> substring — and lexical hits show the matched snippet.</p><p>In <code>hybrid</code> mode the engine <strong>weights the lexical arm by the shape of your query</strong>, so you don&#39;t have to tune anything: a natural-language sentence leans almost fully semantic (keyword coincidences can&#39;t crowd out the conceptual answer), while a quoted <code>&quot;exact phrase&quot;</code>, a boolean (<code>AND</code>/<code>OR</code>/<code>NOT</code>), or a bare code-shaped symbol leans lexical. Overlapping hits (a sliding window that contains a definition, or the same span found by several methods) are <strong>collapsed before the top-N cut</strong>, so you get distinct results rather than repeats of one span — but pure exact-symbol hunts still belong in <code>grep_code</code>.</p><h3 id="Structured-Output-and-Filters" tabindex="-1">Structured Output and Filters <a class="header-anchor" href="#Structured-Output-and-Filters" aria-label="Permalink to &quot;Structured Output and Filters {#Structured-Output-and-Filters}&quot;">​</a></h3><p><code>search_code</code> takes two more options for programmatic and scoped use:</p><ul><li><p><code>format=&quot;structured&quot;</code> returns a JSON array of hits — <code>{point_id, name, file, type, start_line, end_line, text, snippet, sources, score}</code> — instead of the ranked text.</p></li><li><p><code>filters={field: [allowed values]}</code> restricts results to indexed chunks whose <code>metadata</code> matches (AND across fields, any-of within a field), applied in-query on both the vector and lexical engines so <code>limit</code> is honoured after filtering.</p></li></ul><h3 id="resilience" tabindex="-1">Resilience <a class="header-anchor" href="#resilience" aria-label="Permalink to &quot;Resilience&quot;">​</a></h3><p>Hybrid mode degrades gracefully: if embeddings are unavailable (Ollama down or a missing model) or Qdrant is unreachable, search automatically falls back to lexical-only results with a note, instead of failing. The lexical index is local, so basic search keeps working through service outages.</p><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><p>Semantic search requires two external services running locally:</p><ul><li><p><strong>Qdrant</strong> — a vector database that stores and searches embeddings.</p></li><li><p><strong>Ollama</strong> — a local model runner that generates embeddings from text.</p></li></ul><h3 id="Setting-Up-Qdrant" tabindex="-1">Setting Up Qdrant <a class="header-anchor" href="#Setting-Up-Qdrant" aria-label="Permalink to &quot;Setting Up Qdrant {#Setting-Up-Qdrant}&quot;">​</a></h3><p>Start Qdrant using Docker:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qdrant</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 6333:6333</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qdrant_storage:/qdrant/storage</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  qdrant/qdrant</span></span></code></pre></div><p>This runs Qdrant on the default port (<code>6333</code>). Kaimon connects to it automatically. The <code>-v qdrant_storage:/qdrant/storage</code> volume persists your index across container restarts and reboots.</p><h3 id="Setting-Up-Ollama" tabindex="-1">Setting Up Ollama <a class="header-anchor" href="#Setting-Up-Ollama" aria-label="Permalink to &quot;Setting Up Ollama {#Setting-Up-Ollama}&quot;">​</a></h3><p>Install Ollama from <a href="https://ollama.com" target="_blank" rel="noreferrer">ollama.com</a>, then pull the default embedding model:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ollama</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pull</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qwen3-embedding:0.6b</span></span></code></pre></div><p>The Search tab will show a health indicator for both services. If either is not running, the indicator turns red with an error message.</p><h2 id="Indexing-a-Project" tabindex="-1">Indexing a Project <a class="header-anchor" href="#Indexing-a-Project" aria-label="Permalink to &quot;Indexing a Project {#Indexing-a-Project}&quot;">​</a></h2><p>Before you can search, index the project. From the Search tab press <code>i</code>, or use the MCP tool directly:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>qdrant_index_project()</span></span>
<span class="line"><span>qdrant_index_project(project_path=&quot;/path/to/project&quot;)</span></span>
<span class="line"><span>qdrant_index_project(recreate=true)   # rebuild from scratch</span></span></code></pre></div><p>Indexing scans <code>.jl</code>, <code>.ts</code>, <code>.tsx</code>, <code>.jsx</code>, and <code>.md</code> files under the project&#39;s <code>src/</code>, <code>test/</code>, and <code>scripts/</code> directories. It splits them into chunks, computes embeddings, and stores everything in a Qdrant collection named after the project.</p><h3 id="auto-indexing" tabindex="-1">Auto-Indexing <a class="header-anchor" href="#auto-indexing" aria-label="Permalink to &quot;Auto-Indexing&quot;">​</a></h3><p>When a Julia REPL gate connects to Kaimon, the server automatically indexes its project in the background:</p><ul><li><p>If no collection exists yet, Kaimon detects the project type and runs a full index.</p></li><li><p>If a collection already exists, Kaimon runs an incremental sync to pick up any changed files.</p></li></ul><p>File-change notifications from the gate trigger incremental re-indexing automatically, with a 5-second debounce to batch rapid edits.</p><h3 id="Backfilling-the-Lexical-Index" tabindex="-1">Backfilling the Lexical Index <a class="header-anchor" href="#Backfilling-the-Lexical-Index" aria-label="Permalink to &quot;Backfilling the Lexical Index {#Backfilling-the-Lexical-Index}&quot;">​</a></h3><p>The lexical index is populated automatically as files are indexed or re-indexed. For collections that were indexed before hybrid search existed, you can build the lexical index from the existing Qdrant payloads — <strong>without re-embedding</strong> — by running once from the REPL:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Kaimon</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">backfill_fts!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;MyProject&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># one collection</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Kaimon</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">backfill_fts_all!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># every indexed collection</span></span></code></pre></div><p>A normal <code>qdrant_sync_index</code> or reindex also fills it in.</p><h2 id="The-Search-Tab" tabindex="-1">The Search Tab <a class="header-anchor" href="#The-Search-Tab" aria-label="Permalink to &quot;The Search Tab {#The-Search-Tab}&quot;">​</a></h2><p>Press <code>4</code> in the TUI to open the Search tab. It has three panes:</p><p><strong>Status pane</strong> (top) — shows Qdrant and Ollama health, the active collection, and the current embedding model.</p><p><strong>Query pane</strong> (middle) — type your search query here.</p><p><strong>Results pane</strong> (bottom) — scrollable list of matching code chunks with relevance scores.</p><h3 id="Running-a-Search" tabindex="-1">Running a Search <a class="header-anchor" href="#Running-a-Search" aria-label="Permalink to &quot;Running a Search {#Running-a-Search}&quot;">​</a></h3><ol><li><p>Press <code>/</code> to focus the query input.</p></li><li><p>Type your query in plain language.</p></li><li><p>Press <code>Enter</code> to run the search.</p></li><li><p>Use <code>Tab</code> to move focus to the results pane, then <code>↑</code>/<code>↓</code> to scroll.</p></li></ol><h3 id="Switching-Collections" tabindex="-1">Switching Collections <a class="header-anchor" href="#Switching-Collections" aria-label="Permalink to &quot;Switching Collections {#Switching-Collections}&quot;">​</a></h3><p>If you have multiple projects indexed, use <code>↑</code>/<code>↓</code> in the status pane to cycle through available collections. The active collection is highlighted.</p><h3 id="Filtering-by-Chunk-Type" tabindex="-1">Filtering by Chunk Type <a class="header-anchor" href="#Filtering-by-Chunk-Type" aria-label="Permalink to &quot;Filtering by Chunk Type {#Filtering-by-Chunk-Type}&quot;">​</a></h3><p>Press <code>d</code> to cycle through chunk type filters:</p><table tabindex="0"><thead><tr><th style="text-align:right;">Filter</th><th style="text-align:right;">What it returns</th></tr></thead><tbody><tr><td style="text-align:right;"><code>all</code> (default)</td><td style="text-align:right;">Both definition chunks and window chunks</td></tr><tr><td style="text-align:right;"><code>definitions</code></td><td style="text-align:right;">Only functions, structs, macros, and constants</td></tr><tr><td style="text-align:right;"><code>windows</code></td><td style="text-align:right;">Only sliding-window context chunks</td></tr></tbody></table><p>Use <code>definitions</code> when looking for a specific function or type. Use <code>windows</code> when you need broader context that spans multiple definitions.</p><h3 id="Key-Reference" tabindex="-1">Key Reference <a class="header-anchor" href="#Key-Reference" aria-label="Permalink to &quot;Key Reference {#Key-Reference}&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Key</th><th style="text-align:right;">Action</th></tr></thead><tbody><tr><td style="text-align:right;"><code>/</code></td><td style="text-align:right;">Focus query input</td></tr><tr><td style="text-align:right;"><code>Enter</code></td><td style="text-align:right;">Submit query (when input focused)</td></tr><tr><td style="text-align:right;"><code>Tab</code></td><td style="text-align:right;">Cycle pane focus</td></tr><tr><td style="text-align:right;"><code>d</code></td><td style="text-align:right;">Cycle chunk type filter</td></tr><tr><td style="text-align:right;"><code>o</code></td><td style="text-align:right;">Open embedding model configuration</td></tr><tr><td style="text-align:right;"><code>m</code></td><td style="text-align:right;">Open collection manager</td></tr><tr><td style="text-align:right;"><code>r</code></td><td style="text-align:right;">Force-refresh service health</td></tr></tbody></table><h2 id="Embedding-Model-Configuration" tabindex="-1">Embedding Model Configuration <a class="header-anchor" href="#Embedding-Model-Configuration" aria-label="Permalink to &quot;Embedding Model Configuration {#Embedding-Model-Configuration}&quot;">​</a></h2><p>Press <code>o</code> to open the model configuration overlay. This shows all supported embedding models with their vector dimensions, context window size, and whether they are installed in Ollama.</p><table tabindex="0"><thead><tr><th style="text-align:right;">Model</th><th style="text-align:right;">Dimensions</th><th style="text-align:right;">Context</th><th style="text-align:right;">Notes</th></tr></thead><tbody><tr><td style="text-align:right;"><code>qwen3-embedding:0.6b</code></td><td style="text-align:right;">1024</td><td style="text-align:right;">8192 tokens</td><td style="text-align:right;"><strong>Default</strong> — best balance of quality, speed, and size</td></tr><tr><td style="text-align:right;"><code>qwen3-embedding:4b</code></td><td style="text-align:right;">2560</td><td style="text-align:right;">8192 tokens</td><td style="text-align:right;">Highest quality, 4x larger</td></tr><tr><td style="text-align:right;"><code>qwen3-embedding:8b</code></td><td style="text-align:right;">4096</td><td style="text-align:right;">8192 tokens</td><td style="text-align:right;">Largest model</td></tr><tr><td style="text-align:right;"><code>embeddinggemma:latest</code></td><td style="text-align:right;">768</td><td style="text-align:right;">2048 tokens</td><td style="text-align:right;">Most consistent on Julia code</td></tr><tr><td style="text-align:right;"><code>nomic-embed-text:latest</code></td><td style="text-align:right;">768</td><td style="text-align:right;">512 tokens</td><td style="text-align:right;">Lightweight alternative</td></tr><tr><td style="text-align:right;"><code>snowflake-arctic-embed:latest</code></td><td style="text-align:right;">1024</td><td style="text-align:right;">512 tokens</td><td style="text-align:right;">Not recommended</td></tr></tbody></table><h3 id="Switching-Models" tabindex="-1">Switching Models <a class="header-anchor" href="#Switching-Models" aria-label="Permalink to &quot;Switching Models {#Switching-Models}&quot;">​</a></h3><p>Press <code>o</code> from the Search tab to open the model configuration overlay. Navigate with <code>↑</code>/<code>↓</code> and press <code>Enter</code> to select a model. Select &quot;Custom...&quot; at the bottom to enter any Ollama model name manually.</p><p>If the new model has a different vector dimension than the current collection, Kaimon will warn you and prompt you to reindex (<code>y</code>/<code>n</code>). Press <code>y</code> to reindex all connected project collections with the new model.</p><p>Your model choice is saved to <code>~/.config/kaimon/search.json</code> and persists across restarts.</p><p>Changing the embedding model requires reindexing — vectors from different models are not compatible. If you search and see a &quot;dimension mismatch&quot; error, press <code>o</code>, confirm the correct model is selected, and reindex.</p><h2 id="Collection-Manager" tabindex="-1">Collection Manager <a class="header-anchor" href="#Collection-Manager" aria-label="Permalink to &quot;Collection Manager {#Collection-Manager}&quot;">​</a></h2><p>Press <code>m</code> to open the Collection Manager overlay. This shows all indexed projects with their status: vector count, stale file count (files changed since last index), and any active operations.</p><p>From the Collection Manager you can:</p><ul><li><p><strong>Reindex</strong> a collection — re-index all stale files in the background.</p></li><li><p><strong>Delete</strong> a collection — remove it from Qdrant entirely.</p></li><li><p><strong>Add an external project</strong> — index a project that is not currently connected as a gate session. Enter the project path, optionally adjust the source directories and file extensions, then confirm.</p></li></ul><h3 id="Stale-Files" tabindex="-1">Stale Files <a class="header-anchor" href="#Stale-Files" aria-label="Permalink to &quot;Stale Files {#Stale-Files}&quot;">​</a></h3><p>The stale count shows how many files have been modified since the last indexing run. A stale collection will return outdated results for changed code. Use reindex (from the Collection Manager or <code>qdrant_sync_index</code>) to bring it up to date.</p><h2 id="Collection-Management-Tools" tabindex="-1">Collection Management Tools <a class="header-anchor" href="#Collection-Management-Tools" aria-label="Permalink to &quot;Collection Management Tools {#Collection-Management-Tools}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Tool</th><th style="text-align:right;">Description</th></tr></thead><tbody><tr><td style="text-align:right;"><code>qdrant_index_project</code></td><td style="text-align:right;">Index or re-index a project. Use <code>recreate=true</code> to rebuild from scratch.</td></tr><tr><td style="text-align:right;"><code>qdrant_sync_index</code></td><td style="text-align:right;">Sync the index: re-index changed files, remove deleted ones.</td></tr><tr><td style="text-align:right;"><code>qdrant_reindex_file</code></td><td style="text-align:right;">Re-index a single file.</td></tr><tr><td style="text-align:right;"><code>qdrant_browse_collection</code></td><td style="text-align:right;">Browse indexed points with pagination.</td></tr><tr><td style="text-align:right;"><code>qdrant_collection_info</code></td><td style="text-align:right;">Get vector count, size, and configuration for a collection.</td></tr><tr><td style="text-align:right;"><code>qdrant_list_collections</code></td><td style="text-align:right;">List all available collections.</td></tr></tbody></table><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>qdrant_sync_index()</span></span>
<span class="line"><span>qdrant_sync_index(collection=&quot;MyProject&quot;)</span></span></code></pre></div><h2 id="Exact-Pattern-Search-grep_code" tabindex="-1">Exact-Pattern Search (grep_code) <a class="header-anchor" href="#Exact-Pattern-Search-grep_code" aria-label="Permalink to &quot;Exact-Pattern Search (grep_code) {#Exact-Pattern-Search-grep_code}&quot;">​</a></h2><p><code>grep_code</code> is the exact-pattern counterpart to <code>search_code</code>. It runs a real regex over the <strong>live working tree</strong> (no index, so it always reflects the current files), scoped to the bound project by default, and returns every match <code>file:line</code> <strong>with its enclosing function or struct</strong> — so it locates code, not just lines.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>grep_code(pattern=&quot;_eval_with_capture&quot;)          # every occurrence + enclosing symbol</span></span>
<span class="line"><span>grep_code(pattern=&quot;function\\\\s+set_\\\\w+&quot;)         # regex</span></span>
<span class="line"><span>grep_code(pattern=&quot;TODO|FIXME&quot;, glob=[&quot;src/**/*.jl&quot;])</span></span></code></pre></div><p>Reach for it whenever you know the literal text or a regex — a symbol name, a call site, an error string, a <code>TODO</code>. It beats shell <code>grep</code>/<code>rg</code>/<code>find</code>, which aren&#39;t repo-scoped and don&#39;t report the enclosing symbol.</p><p>Key options:</p><table tabindex="0"><thead><tr><th style="text-align:right;">Option</th><th style="text-align:right;">Effect</th></tr></thead><tbody><tr><td style="text-align:right;"><code>path</code> / <code>file</code> / <code>glob</code></td><td style="text-align:right;">Narrow the scope to a subtree, one file, or ripgrep-style globs.</td></tr><tr><td style="text-align:right;"><code>query</code></td><td style="text-align:right;">An optional natural-language intent. Ranks the matching files by semantic relevance and expands context around the relevant hits.</td></tr><tr><td style="text-align:right;"><code>ignore_case</code>, <code>word</code>, <code>fixed</code></td><td style="text-align:right;">Case-insensitive, whole-word, or literal (non-regex) matching.</td></tr><tr><td style="text-align:right;"><code>no_ignore</code></td><td style="text-align:right;">Also search <code>.gitignored</code>/hidden/generated files — so you can grep <strong>logs and build output</strong> without leaving the Kaimon tools.</td></tr><tr><td style="text-align:right;"><code>context</code></td><td style="text-align:right;">Lines of surrounding context per hit.</td></tr></tbody></table><p>Like <code>search_code</code>&#39;s lexical arm, <code>grep_code</code> needs <strong>no external services</strong> — it works with Qdrant and Ollama down.</p>`,82)])])}const u=t(n,[["render",s]]);export{p as __pageData,u as default};
